    public static class ReviewFormatting
    {
        public static IHtmlString ToSafeHtml(string input)
        {
            if (string.IsNullOrEmpty(input)) return MvcHtmlString.Empty;

            var encoded = HttpUtility.HtmlEncode(input);

            var sb = new StringBuilder(encoded.Length + 32);
            for (int i = 0; i < encoded.Length; i++)
            {
                char c = encoded[i];
                if (c == '\r')
                {
                    if (i + 1 < encoded.Length && encoded[i + 1] == '\n') i++;
                    sb.Append("<br />");
                }
                else if (c == '\n')
                {
                    sb.Append("<br />");
                }
                else
                {
                    sb.Append(c);
                }
            }

            var html = sb.ToString();
            html = ReplacePairedMarkup(html, "**", "<strong>", "</strong>");
            html = ReplacePairedMarkup(html, "*", "<em>", "</em>");

            return new MvcHtmlString(html);
        }

        private static string ReplacePairedMarkup(string text, string token, string openTag, string closeTag)
        {
            if (string.IsNullOrEmpty(text)) return text;

            int idx = 0;
            bool open = true;

            while (true)
            {
                int pos = text.IndexOf(token, idx, StringComparison.Ordinal);
                if (pos < 0) break;

                text = text.Remove(pos, token.Length).Insert(pos, open ? openTag : closeTag);
                idx = pos + (open ? openTag.Length : closeTag.Length);
                open = !open;
            }

            if (!open)
            {
                int lastOpen = text.LastIndexOf(openTag, StringComparison.Ordinal);
                if (lastOpen >= 0)
                    text = text.Remove(lastOpen, openTag.Length).Insert(lastOpen, HttpUtility.HtmlEncode(token));
            }

            return text;
        }
    }

    public class AppDbContext : DbContext
    {
        public AppDbContext() : base("DefaultConnection") { }

        public DbSet<Product> Products { get; set; }
